const ctx = $('When Called by Router').item.json;
const leadRow = $input.first().json;

const despacho = ctx.nombre_despacho || ctx.abogado_nombre || 'nuestro despacho';
const especialidades = Array.isArray(ctx.especialidades)
  ? ctx.especialidades.join(', ')
  : (ctx.especialidades || 'derecho');

const mensaje = `¡Hola ${ctx.client_name}! 👋\n\nBienvenido/a a *${despacho}*. Soy el asistente virtual y estoy aquí para ayudarte.\n\n⚖️ Nos especializamos en: ${especialidades}.\n\nPara brindarte la mejor orientación, cuéntame brevemente: *¿En qué tipo de asunto legal necesitas apoyo?*`;

return [{
  json: {
    ...ctx,
    lead_id: leadRow.id || ctx.lead_id,
    lead_estado: leadRow.estado || 'nuevo',
    mensaje_saludo: mensaje
  }
}];
